mapper.select:
/* usimMgmtMapper.getUsimMgmtList */
SELECT USIM_NO , USIM_NO AS USIM_NO_MSK , ORGN_ID , FN_GET_ORGNM(ORGN_ID) AS ORGN_NM , REGST_ID , TO_CHAR(REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM , RVISN_ID , TO_CHAR(RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM , DELIVERY_DTTM , ORDER_NUM , USIM_PRDT_ID , USIM_PRDT_CODE FROM MSP_PARTNER_USIM_MST WHERE 1=1
AND ORGN_ID = #{orgnId}
AND USIM_NO = #{usimNo}
AND REGST_DTTM BETWEEN TO_DATE(#{searchFromDt}||'000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{searchToDt}||'235959', 'YYYYMMDDHH24MISS')
ORDER BY NVL(RVISN_DTTM, REGST_DTTM) DESC, REGST_DTTM DESC, USIM_NO DESC

/* usimMgmtMapper.getActiveUsimList */
SELECT JSI.LST_COM_ACTV_DATE , JSI.CONTRACT_NUM , DECODE(JSI.SUB_STATUS, 'A', '사용중', 'S', '정지', 'C', '해지', 'R', '예약', JSI.SUB_STATUS) STATUS , FN_GET_ORGNM(JSI.OPEN_AGNT_CD) AS AGENT_NM , TO_CHAR(TO_DATE(DECODE(JSI.SUB_STATUS,'C',SUBSTR(JSI.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS TMNT_DT , CASE WHEN JSI.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN , PUM.USIM_NO , PUM.ORGN_ID , FN_GET_ORGNM(PUM.ORGN_ID) AS ORGN_NM , TO_CHAR(TO_DATE(MRD.REQ_IN_DAY,'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY , MRD.FST_RATE_NM FROM MSP_PARTNER_USIM_MST PUM, MSP_JUO_SUB_INFO JSI, MSP_REQUEST_DTL MRD WHERE JSI.CONTRACT_NUM = MRD.CONTRACT_NUM --AND NVL(TRIM(SUBSTR(MRD.FST_MODEL_INFO, 51 , 30)), JSI.ICC_ID) = PUM.USIM_NO AND MRD.FST_USIM_NO = PUM.USIM_NO
AND PUM.ORGN_ID = #{orgnId}
AND JSI.LST_COM_ACTV_DATE BETWEEN #{searchFromDt} AND #{searchToDt}
ORDER BY JSI.LST_COM_ACTV_DATE DESC

/* usimMgmtMapper.getActiveUsimListByExcel */ SELECT JSI.LST_COM_ACTV_DATE , JSI.CONTRACT_NUM , DECODE(JSI.SUB_STATUS, 'A', '사용중', 'S', '정지', 'C', '해지', 'R', '예약', JSI.SUB_STATUS) STATUS , FN_GET_ORGNM(JSI.OPEN_AGNT_CD) AS AGENT_NM , TO_CHAR(TO_DATE(DECODE(JSI.SUB_STATUS,'C',SUBSTR(JSI.SUB_STATUS_DATE,1,8),''),'YYYYMMDD'),'YYYY-MM-DD') AS TMNT_DT , CASE WHEN JSI.SUB_STATUS = 'C' THEN CASE WHEN 0 = TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '당일개통취소' WHEN 15 > TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '14일이내해지' WHEN 90 > TO_DATE(SUBSTR(JSI.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(JSI.LST_COM_ACTV_DATE, 'YYYYMMDD') THEN '90일이내해지' ELSE '일반해지' END ELSE '' END AS CAN_RSN , PUM.USIM_NO , PUM.ORGN_ID , FN_GET_ORGNM(PUM.ORGN_ID) AS ORGN_NM , TO_CHAR(TO_DATE(MRD.REQ_IN_DAY,'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD HH24:MI:SS') AS REQ_IN_DAY , MRD.FST_RATE_NM FROM MSP_PARTNER_USIM_MST PUM, MSP_JUO_SUB_INFO JSI, MSP_REQUEST_DTL MRD WHERE JSI.CONTRACT_NUM = MRD.CONTRACT_NUM --AND NVL(TRIM(SUBSTR(MRD.FST_MODEL_INFO, 51 , 30)), JSI.ICC_ID) = PUM.USIM_NO AND MRD.FST_USIM_NO = PUM.USIM_NO
AND PUM.ORGN_ID = #{orgnId}
AND JSI.LST_COM_ACTV_DATE BETWEEN #{searchFromDt} AND #{searchToDt}
ORDER BY JSI.LST_COM_ACTV_DATE DESC

SELECT 	COUNT(USIM_NO)
FROM	MSP_PARTNER_USIM_MST
WHERE	USIM_NO = #{usimNo}

mapper.insert:
/* usimMgmtMapper.insertUsimMgmt */
INSERT INTO MSP_PARTNER_USIM_MST (
	USIM_NO
	, ORGN_ID
	, REGST_ID
	, REGST_DTTM
	, DELIVERY_DTTM
	, ORDER_NUM
	, USIM_PRDT_ID
	, USIM_PRDT_CODE			
) VALUES (
	#{usimNo, jdbcType=VARCHAR}
	, #{orgnId, jdbcType=VARCHAR}
	, #{sessionUserId, jdbcType=VARCHAR}
	, SYSDATE
	, #{deliveryDttm, jdbcType=VARCHAR}
	, #{orderNum, jdbcType=VARCHAR}
	, #{usimPrdtId, jdbcType=VARCHAR}
	, #{usimPrdtCode, jdbcType=VARCHAR}
)

mapper.update:
/* usimMgmtMapper.updateUsimMgmt */
UPDATE	MSP_PARTNER_USIM_MST
SET		ORGN_ID = #{orgnId, jdbcType=VARCHAR}
		, RVISN_ID = #{sessionUserId, jdbcType=VARCHAR}
		, RVISN_DTTM = SYSDATE
WHERE	USIM_NO = #{usimNo, jdbcType=VARCHAR}

mapper.delete:
/* usimMgmtMapper.deleteUsimMgmt */
DELETE	FROM MSP_PARTNER_USIM_MST
WHERE	USIM_NO = #{usimNo, jdbcType=VARCHAR}

mapper.insert:
/* usimMgmtMapper."insertUsimHist" */
INSERT INTO MSP_PARTNER_USIM_HIST (
	USIM_NO
	, ORGN_ID
	, EVNT_SEQ
	, EVNT_CD
	, EVNT_REGST_ID
	, EVNT_DTTM
	, DELIVERY_DTTM
	, ORDER_NUM
	, USIM_PRDT_ID
	, USIM_PRDT_CODE
) VALUES (
	#{usimNo, jdbcType=VARCHAR}
	, #{orgnId, jdbcType=VARCHAR}
	, (SELECT NVL(MAX(EVNT_SEQ)+1,1) FROM MSP_PARTNER_USIM_HIST WHERE USIM_NO = #{usimNo, jdbcType=VARCHAR})
	, #{evntCd, jdbcType=VARCHAR}
	, #{sessionUserId, jdbcType=VARCHAR}
	, SYSDATE
	, #{deliveryDttm, jdbcType=VARCHAR}
	, #{orderNum, jdbcType=VARCHAR}
	, #{usimPrdtId, jdbcType=VARCHAR}
	, #{usimPrdtCode, jdbcType=VARCHAR}

)

